**1. `docs/schema.sql` 파일 생성:**

```sql
CREATE TABLE public.users (
  id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,
  email TEXT NOT NULL,
  name TEXT,
  provider TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL
);

CREATE TABLE public.events (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  host_id UUID REFERENCES public.users(id) ON DELETE CASCADE NOT NULL,
  title TEXT NOT NULL,
  date TIMESTAMPTZ NOT NULL,
  location TEXT NOT NULL,
  fee INTEGER DEFAULT 0 NOT NULL,
  capacity INTEGER,
  created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL
);

CREATE TYPE participant_status AS ENUM ('applied', 'canceled');
CREATE TYPE payment_status AS ENUM ('unpaid', 'paid');

CREATE TABLE public.participants (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  event_id UUID REFERENCES public.events(id) ON DELETE CASCADE NOT NULL,
  name TEXT NOT NULL,
  email TEXT,
  is_email_opt_in BOOLEAN DEFAULT FALSE NOT NULL,
  status participant_status DEFAULT 'applied' NOT NULL,
  attended BOOLEAN,
  payment_status payment_status DEFAULT 'unpaid' NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL
);

CREATE TABLE public.notices (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  event_id UUID REFERENCES public.events(id) ON DELETE CASCADE NOT NULL,
  content TEXT NOT NULL,
  send_email BOOLEAN DEFAULT FALSE NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL
);

-- RLS 활성화 및 정책 적용
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.events ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.participants ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.notices ENABLE ROW LEVEL SECURITY;

CREATE POLICY "users_self" ON public.users FOR ALL USING (auth.uid() = id);
CREATE POLICY "events_host" ON public.events FOR ALL USING (host_id = auth.uid());
CREATE POLICY "participants_insert" ON public.participants FOR INSERT WITH CHECK (true);
CREATE POLICY "participants_host_select" ON public.participants FOR SELECT USING (
  EXISTS (SELECT 1 FROM public.events WHERE id = participants.event_id AND host_id = auth.uid())
);
CREATE POLICY "participants_host_update" ON public.participants FOR UPDATE USING (
  EXISTS (SELECT 1 FROM public.events WHERE id = participants.event_id AND host_id = auth.uid())
);
CREATE POLICY "notices_host_write" ON public.notices FOR ALL USING (
  EXISTS (SELECT 1 FROM public.events WHERE id = notices.event_id AND host_id = auth.uid())
);
CREATE POLICY "notices_public_read" ON public.notices FOR SELECT USING (true);

-- auth trigger
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.users (id, email, name, provider)
  VALUES (NEW.id, NEW.email, NEW.raw_user_meta_data->>'full_name', NEW.raw_app_meta_data->>'provider');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();
```

