```typescript
export async function createNotice(eventId: string, formData: FormData) {
  const content = formData.get('content') as string;
  const sendEmail = formData.get('send_email') === 'true';

  const supabase = await createClient();
  await supabase.from('notices').insert({ event_id: eventId, content, send_email: sendEmail });

  if (sendEmail) {
    const resend = new Resend(process.env.RESEND_API_KEY);
    // is_email_opt_in=true, status=applied 참여자에게만 발송
    const { data: recipients } = await supabase
      .from('participants')
      .select('name, email')
      .eq('event_id', eventId)
      .eq('status', 'applied')
      .eq('is_email_opt_in', true)
      .not('email', 'is', null);

    if (recipients?.length) {
      await Promise.all(
        recipients.map(p =>
          resend.emails.send({
            from: 'GroupMeet <noreply@yourdomain.com>',
            to: p.email!,
            subject: `새 공지가 등록되었습니다`,
            html: `<p>${p.name}님,</p><p>${content}</p>`,
          })
        )
      );
    }
  }
}
```

